def maybe_summarise(thread):
    block = thread.unsummarised_messages()
    if tokens(block) < SUMMARY_THRESHOLD:
        return                                 # not enough material yet

    summary = llm.summarise(
        block,
        instructions="Preserve gist: decisions, facts, open questions."
    )
    summary_store.append({
        "thread": thread.id,
        "range": (block[0].id, block[-1].id),
        "text": summary,
        "ts": now(),
    })
    archive.move(block)                        # originals go cold, not deleted

def load_for_turn(thread):
    # Reads always consult the summary tier first.
    summaries = summary_store.recent(thread.id, k=5)
    recent    = thread.tail(n=10)
    return [system_prompt(history_summary=summaries), *recent]

function ingest(observation):
    # 1. Extract typed entities and relations.
    triples = llm.extract(
        observation,
        schema="(:Entity {id, type, name}) -[:REL {type}]-> (:Entity ...)"
    )
    # 2. Upsert into the graph store.
    for (h, r, t) in triples:
        graph.merge_node(h); graph.merge_node(t)
        graph.merge_edge(h, r, t)
        vector_index.add(h.id, embed(h.name))   # entry-point embedding

function query(question):
    # Vector finds plausible entry points; graph traverses from there.
    seeds = vector_index.search(embed(question), k=3)
    subgraph = graph.expand(seeds, depth=2)
    return llm.answer(question, evidence=subgraph)

# Episode = [user_turn, (assistant + tool_calls + tool_results)*, assistant_final]
# Reasoning trace is episode-scoped.

def build_context(history):
    out = []
    # 1. Find the start of the CURRENT episode = index of the last user msg.
    last_user = max(i for i, m in enumerate(history) if m.role == "user")

    for i, msg in enumerate(history):
        if msg.role == "assistant":
            if i >= last_user:
                # Inside current episode — preserve reasoning_content so the
                # model can chain its own thinking across tool round-trips.
                out.append(msg)              # includes reasoning_content
            else:
                # Past episode — strip reasoning, keep only user-visible text.
                out.append(msg.without_reasoning())
        else:
            out.append(msg)                  # user / tool messages unchanged
    return out

# At the next user turn the previous reasoning_content silently drops; the
# API would reject or ignore stale reasoning blocks across episodes anyway.

# Weights are persisted in a config so a reflection pass can adjust them.
weights = load_yaml("salience.yaml")  # alpha, beta, gamma, delta, epsilon

def salience(item, goal, ctx):
    return (
        weights["alpha"]   * novelty(item, ctx.recent_attended)
      + weights["beta"]    * goal_relevance(item, goal)
      + weights["gamma"]   * recency(item, now())
      + weights["delta"]   * prediction_error(item, ctx.last_prediction)
      - weights["epsilon"] * fatigue(item, ctx.attention_log)
        # fatigue penalises items attended N times in the recent window;
        # this is what breaks rumination loops on the same memory.
    )

def select_working_set(candidates, goal, ctx, k=7):
    scored = [(salience(c, goal, ctx), c) for c in candidates]
    scored.sort(reverse=True)
    chosen = [c for _, c in scored[:k]]
    for c in chosen:
        ctx.attention_log.record(c.id, now())   # feeds future fatigue term
    return chosen

class Scratchpad:
    def __init__(self): self._lines = []
    def read(self):    return "\n".join(self._lines)
    def write(self, line): self._lines.append(line)
    def clear(self):   self._lines = []

scratch = Scratchpad()

tools = [
    Tool("scratch_read",  lambda: scratch.read()),
    Tool("scratch_write", lambda line: scratch.write(line)),
]

function handle_turn(user_msg):
    messages = [
        system_prompt(
            "You have a scratchpad. Use scratch_write for intermediate "
            "notes that should NOT appear in your reply. Read it whenever "
            "you need to recall something you wrote earlier."
        ),
        {"role": "system", "content": f"Scratchpad:\n{scratch.read()}"},
        user(user_msg),
    ]
    reply = agent_loop(messages, tools)
    return reply.content    # scratchpad contents never leak into the reply

on_task_complete(lambda: scratch.clear())   # purge at completion

@dataclass
class ThreadState:
    messages:    list
    active_plan: dict | None
    screen:      str | None
    agent_step:  int
    updated_at:  float

store = KV()  # any TTL-aware KV: Redis, DynamoDB w/ TTL, etc.
TTL = 24 * 3600

def load(thread_id) -> ThreadState:
    raw = store.get(thread_id)
    if not raw or now() - raw["updated_at"] > TTL:
        return ThreadState(messages=[], active_plan=None,
                           screen=None, agent_step=0,
                           updated_at=now())   # expired -> reset
    return ThreadState(**raw)

def save(thread_id, st: ThreadState):
    st.updated_at = now()
    store.put(thread_id, asdict(st), ttl=TTL)

function handle_turn(thread_id, user_msg):
    st = load(thread_id)
    st.messages.append(user(user_msg))
    reply = llm.generate(messages=st.messages, state=st)
    st.messages.append(reply); st.agent_step += 1
    save(thread_id, st)
    return reply.content
